func TestEnumPromptType(t *testing.T) {
	t.Run("NewFromString_chat", func(t *testing.T) {
		t.Parallel()
		val, err := NewPromptTypeFromString("chat")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, PromptType("chat"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_text", func(t *testing.T) {
		t.Parallel()
		val, err := NewPromptTypeFromString("text")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, PromptType("text"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewPromptTypeFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewPromptTypeFromString("chat")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

